/**
 * @fileoverview JIT Component Rule Generator
 *
 * Converts a ComponentDefinition into CSS rules that the JIT engine
 * can inject. Provides helpers for:
 *   - Token -> CSS custom property declarations
 *   - State -> CSS state-based rules (`.is-open`, `.is-disabled`, etc.)
 *   - Structural styles -> atomic CSS class mapping + scoped rules
 *   - Variant -> modifier CSS rules
 *
 * Used internally by `JIT.defineComponent()` and available for
 * DevPanel introspection and testing.
 *
 * @module core/rules
 */

// в”Ђв”Ђ Token -> CSS Custom Property в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Generate CSS custom property declarations from component tokens.
 *
 * @param {string} prefix - Component token prefix (e.g., 'acc').
 * @param {Object<string, {ref?: string, value?: string}>} tokens - Token definitions.
 * @param {Function} resolveRef - Resolver function (ref -> CSS value).
 * @returns {string[]} Array of 'varName: value' declaration strings.
 *
 * @example
 *   buildTokenDeclarations('acc', {
 *       'radius':    { ref: 'radius.md' },
 *       'font-size': { ref: 'font.size-sm' },
 *   }, resolveRef);
 *   // -> ['--acc-radius: 6px', '--acc-font-size: 0.85rem']
 */
function buildTokenDeclarations(prefix, tokens, resolveRef) {
    const declarations = [];
    
    // Iterate over each token definition
    for (const [key, def] of Object.entries(tokens)) {
        // Construct the CSS custom property name
        const varName = `--${prefix}-${key}`;
        
        // If the token has a reference and a resolver is provided, resolve it
        if (def.ref && resolveRef) {
            declarations.push(`${varName}: ${resolveRef(def.ref)}`);
        } 
        // Otherwise, if it has a direct value, use it
        else if (def.value) {
            declarations.push(`${varName}: ${def.value}`);
        }
    }
    
    return declarations;
}

// в”Ђв”Ђ State -> CSS Rules в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Generate state-based CSS rules from a state machine definition.
 *
 * Each state that has a `class` and `styles` property produces a CSS
 * rule targeting that class on the block element (or a child target).
 *
 * @param {string} blockClass - The component root class (e.g., 'accordion').
 * @param {Object<string, {target?: string, class?: string, styles?: Object<string, string>}>} states - State definitions.
 * @returns {string[]} Array of CSS rule strings.
 *
 * @example
 *   buildStateRules('accordion', {
 *       open:     { class: 'is-open',     styles: { 'max-height': '100vh', opacity: '1' } },
 *       closed:   { class: 'is-closed',   styles: { 'max-height': '0', opacity: '0' } },
 *       disabled: { class: 'is-disabled', styles: { opacity: '0.5', 'pointer-events': 'none' } },
 *   });
 *   // -> [
 *   //     '.accordion.is-open { max-height: 100vh; opacity: 1; }',
 *   //     '.accordion.is-closed { max-height: 0; opacity: 0; }',
 *   //     '.accordion.is-disabled { opacity: 0.5; pointer-events: none; }',
 *   // ]
 */
function buildStateRules(blockClass, states) {
    const rules = [];
    
    // Iterate over each state configuration
    for (const [, stateConfig] of Object.entries(states)) {
        // Only process states that have explicit CSS class and styles mappings
        if (!stateConfig?.class || !stateConfig?.styles) continue;

        const { target, class: cls, styles } = stateConfig;
        
        // Construct the CSS selector based on whether a target is specified
        const selector = target
            ? `.${blockClass} ${target}.${cls}`
            : `.${blockClass}.${cls}`;
            
        // Convert the styles object into a CSS rule body string
        const body = Object.entries(styles)
            .map(([p, v]) => `${p}: ${v}`)
            .join('; ');
            
        // If there are styles, add the complete rule to the array
        if (body) {
            rules.push(`${selector} { ${body}; }`);
        }
    }
    
    return rules;
}

// в”Ђв”Ђ Structural -> Atomic CSS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Map of CSS property:value pairs to JIT utility class names.
 * Used to convert structural style declarations into atomic classes
 * where a direct mapping exists.
 */
const UTILITY_MAP = {
    'display:flex':              'flex',
    'display:inline-flex':       'inline-flex',
    'display:grid':              'grid',
    'display:block':             'block',
    'display:inline-block':      'inline-block',
    'display:none':              'hidden',
    'flex-direction:column':     'flex-col',
    'flex-direction:row':        'flex-row',
    'align-items:center':        'items-center',
    'align-items:start':         'items-start',
    'align-items:end':           'items-end',
    'align-items:stretch':       'items-stretch',
    'justify-content:center':    'justify-center',
    'justify-content:space-between': 'justify-between',
    'justify-content:flex-start': 'justify-start',
    'justify-content:flex-end':  'justify-end',
    'position:relative':         'relative',
    'position:absolute':         'absolute',
    'position:fixed':            'fixed',
    'position:sticky':           'sticky',
    'overflow:hidden':           'overflow-hidden',
    'overflow:auto':             'overflow-auto',
    'overflow:scroll':           'overflow-scroll',
    'cursor:pointer':            'cursor-pointer',
    'cursor:default':            'cursor-default',
    'cursor:not-allowed':        'cursor-not-allowed',
    'cursor:grab':               'cursor-grab',
    'cursor:move':               'cursor-move',
    'pointer-events:none':       'pointer-events-none',
    'user-select:none':          'select-none',
    'white-space:nowrap':        'text-nowrap',
    'text-align:center':         'text-center',
    'text-align:left':           'text-left',
    'text-align:right':          'text-right',
    'width:100%':                'w-full',
    'height:100%':               'h-full',
    'width:auto':                'w-auto',
    'height:auto':               'h-auto',
    'flex:1':                    'flex-1',
    'flex-shrink:0':             'shrink-0',
    'flex-grow:0':               'grow-0',
    'flex-grow:1':               'grow',
    'flex-wrap:wrap':            'flex-wrap',
    'flex-wrap:nowrap':          'flex-nowrap',
    'opacity:0':                 'opacity-0',
    'opacity:1':                 'opacity-100',
    'visibility:hidden':         'invisible',
    'visibility:visible':        'visible',
};

/**
 * Convert structural style declarations into atomic CSS classes (where possible)
 * and component-scoped CSS rules (for the remainder).
 *
 * @param {Object<string, string>} styles - CSS property to value pairs.
 * @returns {{ utilities: string[], scoped: string[] }} Object containing utility classes and scoped rules.
 *
 * @example
 *   mapToAtomicClasses({
 *       display: 'flex',
 *       'flex-direction': 'column',
 *       'border-radius': 'var(--acc-radius)',
 *   });
 *   // -> { utilities: ['flex', 'flex-col'], scoped: ['border-radius: var(--acc-radius)'] }
 */
function mapToAtomicClasses(styles) {
    const result = { utilities: [], scoped: [] };
    
    // Iterate over each style property and value
    for (const [prop, val] of Object.entries(styles)) {
        // Create a key to look up in the utility map
        const key = `${prop}:${val}`;
        
        // If a utility class exists for this property-value pair, use it
        if (UTILITY_MAP[key]) {
            result.utilities.push(UTILITY_MAP[key]);
        } 
        // Otherwise, keep it as a scoped CSS rule
        else {
            result.scoped.push(`${prop}: ${val}`);
        }
    }
    
    return result;
}

function stringifyStyleBody(styles) {
    if (!styles) return '';
    if (typeof styles === 'string') return styles.trim().replace(/;$/, '');
    return Object.entries(styles)
        .map(([prop, value]) => `${prop}: ${value}`)
        .join('; ');
}

function resolveStyleSelector(blockClass, selectorKey) {
    if (selectorKey === 'root' || selectorKey === '&') return `.${blockClass}`;
    if (selectorKey.includes('&')) {
        return selectorKey.replace(/&/g, `.${blockClass}`);
    }
    return `.${blockClass}-${selectorKey}`;
}

function buildKeyframeRule(name, frames) {
    if (!frames || typeof frames !== 'object') return '';
    const body = Object.entries(frames)
        .map(([step, styles]) => `${step} { ${stringifyStyleBody(styles)}; }`)
        .join(' ');
    return body ? `${name} { ${body} }` : '';
}

function buildNestedAtRule(blockClass, atRule, entries) {
    const rules = [];
    for (const [selectorKey, styles] of Object.entries(entries || {})) {
        if (selectorKey.startsWith('@keyframes ')) {
            const keyframeRule = buildKeyframeRule(selectorKey, styles);
            if (keyframeRule) rules.push(keyframeRule);
            continue;
        }

        const selector = resolveStyleSelector(blockClass, selectorKey);
        const body = stringifyStyleBody(styles);
        if (body) rules.push(`${selector} { ${body}; }`);
    }
    return rules.length ? `${atRule} { ${rules.join(' ')} }` : '';
}

// в”Ђв”Ђ Variant -> CSS Rules в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Generate variant CSS rules from a component's variant definitions.
 *
 * @param {string} blockClass - Component root class.
 * @param {Object<string, Object<string, string>>} variants - Variant overrides.
 * @returns {string[]} Array of CSS rule strings.
 *
 * @example
 *   buildVariantRules('accordion', {
 *       boxed: { '--acc-gap': '0.5rem', border: 'none' },
 *   });
 *   // -> ['.accordion.is-boxed { --acc-gap: 0.5rem; border: none; }']
 */
function buildVariantRules(blockClass, variants) {
    const rules = [];
    
    // Iterate over each variant and its overrides
    for (const [variant, overrides] of Object.entries(variants)) {
        // Skip non-style variant entries (like `description`) or invalid overrides
        if (typeof overrides !== 'object' || overrides === null) continue;
        
        // Filter out non-style properties like `description`
        const styleProps = Object.entries(overrides).filter(
            ([k]) => k !== 'description'
        );

        // If there are no style properties left, skip rule generation
        if (styleProps.length === 0) continue;

        // Convert the style properties into a CSS rule body string
        const body = styleProps
            .map(([p, v]) => `${p}: ${v}`)
            .join('; ');
            
        // Add the complete variant rule to the array
        rules.push(`.${blockClass}.is-${variant} { ${body}; }`);
    }
    
    return rules;
}

// в”Ђв”Ђ Full Component CSS Builder в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Build the complete CSS output for a component definition.
 *
 * Generates:
 *   1. Token default declarations on the root class
 *   2. Structural scoped rules (non-atomic remainder)
 *   3. State-based rules
 *   4. Variant rules
 *
 * @param {string} name - PascalCase component name.
 * @param {object} def - ComponentDefinition object.
 * @param {Function} resolveRef - Token reference resolver function.
 * @returns {string} Complete CSS string.
 */
function buildComponentCSS(name, def, resolveRef) {
    // Convert the PascalCase component name to a kebab-case class name
    const blockClass = kebab(name);
    const rules = [];

    // 1. Token defaults on root
    const tokenCfg = def.tokens;
    if (tokenCfg?.prefix && tokenCfg?.tokens) {
        // Generate token declarations
        const declarations = buildTokenDeclarations(
            tokenCfg.prefix,
            tokenCfg.tokens,
            resolveRef
        );
        
        // If there are declarations, add them to the root class rule
        if (declarations.length > 0) {
            rules.push(`.${blockClass} { ${declarations.join('; ')}; }`);
        }
    }

    // 2. Structural styles (scoped)
    if (def.styles) {
        // Iterate over each element and its styles
        for (const [element, styles] of Object.entries(def.styles)) {
            if (element.startsWith('@keyframes ')) {
                const keyframeRule = buildKeyframeRule(element, styles);
                if (keyframeRule) rules.push(keyframeRule);
                continue;
            }

            if (element.startsWith('@media ')) {
                const mediaRule = buildNestedAtRule(blockClass, element, styles);
                if (mediaRule) rules.push(mediaRule);
                continue;
            }

            const selector = resolveStyleSelector(blockClass, element);

            if (typeof styles === 'object' && styles !== null && !element.includes('&') && element !== 'root') {
                const { scoped } = mapToAtomicClasses(styles);
                if (scoped.length) {
                    rules.push(`${selector} { ${scoped.join('; ')}; }`);
                }
                continue;
            }

            const body = stringifyStyleBody(styles);
            if (body) {
                rules.push(`${selector} { ${body}; }`);
            }
        }
    }

    // 3. State rules - extract from states.states if they have class/styles
    if (def.states?.states) {
        // Generate state rules and add them to the rules array
        const stateRules = buildStateRules(blockClass, def.states.states);
        rules.push(...stateRules);
    }

    // 4. Variant rules
    if (def.variants) {
        // Generate variant rules and add them to the rules array
        const variantRules = buildVariantRules(blockClass, def.variants);
        rules.push(...variantRules);
    }

    // Join all rules with a newline character
    return rules.join('\n');
}

/**
 * Convert a PascalCase string to a kebab-case string.
 * 
 * @param {string} str - The PascalCase string to convert.
 * @returns {string} The converted kebab-case string.
 */
function kebab(str) {
    // Replace uppercase letters preceded by lowercase letters with a hyphen and the lowercase letter
    return str.replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase();
}

export {
    buildComponentCSS,
    buildTokenDeclarations,
    buildStateRules,
    buildVariantRules,
    mapToAtomicClasses,
    kebab,
    UTILITY_MAP,
};
