/**
 * style-hash.js вЂ” Fast, deterministic CSS deduplication hashing.
 *
 * Uses FNV-1a (32-bit) for short, collision-resistant hash strings.
 * The output is a 6вЂ“7 character base-36 string suitable for use as
 * a CSS class suffix or cache key segment.
 *
 * Usage:
 *   import { styleHash, cacheKey } from './style-hash.js';
 *   styleHash('.btn { color: red }')   // в†’ 'k4f2m1'
 *   cacheKey('admin', 'light', 'lg')   // в†’ 'admin:light:lg:h7x9p3'
 */

// в”Ђв”Ђ FNV-1a constants в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
const FNV_OFFSET = 0x811c9dc5;
const FNV_PRIME = 0x01000193;

/**
 * Compute FNV-1a 32-bit hash of a string.
 *
 * @param {string} str
 * @returns {number} Unsigned 32-bit integer.
 */
function fnv1a32(str) {
    let hash = FNV_OFFSET;
    for (let i = 0; i < str.length; i++) {
        hash ^= str.charCodeAt(i);
        hash = Math.imul(hash, FNV_PRIME);
    }
    return hash >>> 0; // ensure unsigned
}

/**
 * Hash a CSS string to a short base-36 identifier.
 *
 * @param {string} css - The CSS text to hash.
 * @returns {string} 6вЂ“7 character base-36 hash.
 */
export function styleHash(css) {
    return fnv1a32(css).toString(36);
}

/**
 * Build a composite cache key from layout id, theme, breakpoint,
 * and the hash of the CSS content.
 *
 * @param {string} layoutId   - e.g. 'admin'
 * @param {string} theme      - e.g. 'light', 'dark'
 * @param {string} breakpoint - e.g. 'lg', 'md'
 * @param {string} [css]      - Optional CSS to include in key.
 * @returns {string} Cache key like 'admin:light:lg:k4f2m1'
 */
export function cacheKey(layoutId, theme, breakpoint, css) {
    const parts = [layoutId, theme, breakpoint];
    if (css) parts.push(styleHash(css));
    return parts.join(':');
}
