/**
 * layout.js вЂ” Layout Composition DSL for RazyUI v2.
 *
 * Provides a declarative, function-composition API for defining page layouts.
 * Layouts declare named regions (slots), each with token overrides, and the
 * components that populate them.
 *
 * Usage:
 *   import { Layout, Region } from '../core/layout.js';
 *
 *   const admin = Layout('admin', {
 *       tokens: { 'sidebar-width': '16rem', 'header-height': '3.5rem' },
 *       regions: [
 *           Region('header',  { role: 'banner',        components: ['Navbar'] }),
 *           Region('sidebar', { role: 'navigation',    components: ['Sidebar'] }),
 *           Region('main',    { role: 'main',          components: ['DataTable', 'Card'] }),
 *           Region('footer',  { role: 'contentinfo' }),
 *       ],
 *   });
 *
 *   admin.compile(tokenResolver, depGraph);
 *   // в†’ { id, css, loadOrder, regionMap }
 */

import { DependencyGraph } from './dependency-graph.js';

// в”Ђв”Ђ Region factory в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Create a region descriptor.
 *
 * @param {string}   name                - Unique region name within a layout.
 * @param {object}   [opts={}]
 * @param {string}   [opts.role]         - ARIA landmark role.
 * @param {string}   [opts.tag='div']    - HTML element tag.
 * @param {string[]} [opts.components]   - Component names used in this region.
 * @param {object}   [opts.tokens]       - Region-level token overrides.
 * @param {string}   [opts.styles]       - JIT utility string for the region wrapper.
 * @returns {Readonly<object>}
 */
export function Region(name, opts = {}) {
    return Object.freeze({
        name,
        role: opts.role ?? null,
        tag: opts.tag ?? 'div',
        components: Object.freeze(opts.components ?? []),
        tokens: opts.tokens ? Object.freeze({ ...opts.tokens }) : null,
        styles: opts.styles ?? '',
    });
}

// в”Ђв”Ђ Layout factory в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Create a layout descriptor.
 *
 * @param {string}  id                   - Unique layout identifier (e.g. 'admin').
 * @param {object}  config
 * @param {object}  [config.tokens]      - Layout-level token overrides.
 * @param {Array}   config.regions       - Region descriptors (from Region()).
 * @param {string}  [config.grid]        - CSS grid-template shorthand (optional).
 * @param {object}  [config.areas]       - Named grid areas per region.
 * @returns {LayoutDescriptor}
 */
export function Layout(id, config) {
    const { tokens = {}, regions = [], grid = null, areas = null } = config;

    // Index regions by name for O(1) lookup
    const regionMap = new Map();
    for (const r of regions) {
        if (regionMap.has(r.name)) {
            throw new Error(`Layout '${id}': duplicate region name '${r.name}'`);
        }
        regionMap.set(r.name, r);
    }

    return Object.freeze({
        id,
        tokens: Object.freeze({ ...tokens }),
        regions: Object.freeze([...regions]),
        grid,
        areas: areas ? Object.freeze({ ...areas }) : null,

        /**
         * Look up a region by name.
         * @param {string} name
         * @returns {object|undefined}
         */
        region(name) {
            return regionMap.get(name);
        },

        /**
         * Collect all unique component names referenced by this layout.
         * @returns {string[]}
         */
        componentNames() {
            const set = new Set();
            for (const r of regions) {
                for (const c of r.components) set.add(c);
            }
            return [...set];
        },

        /**
         * Compile the layout against a TokenResolver and DependencyGraph.
         *
         * 1. Registers layout tokens with the resolver
         * 2. Builds a subgraph of only the components this layout uses
         * 3. Produces a load order (topo-sorted)
         * 4. Generates layout wrapper CSS (grid + region vars)
         *
         * @param {import('./token-resolver.js').TokenResolver} resolver
         * @param {DependencyGraph} graph
         * @returns {{ id: string, css: string, loadOrder: string[], regionMap: Map }}
         */
        compile(resolver, graph) {
            // 1. Register layout tokens
            resolver.registerLayout(id, tokens);

            // 2. Collect all components + their transitive deps
            const names = this.componentNames();
            const sub = graph.subgraph(names);
            const loadOrder = sub.sorted();

            // 3. Generate layout CSS
            const cssLines = [];

            // Layout wrapper class
            cssLines.push(`.layout-${id} {`);

            // Token custom properties
            for (const [key, value] of Object.entries(tokens)) {
                cssLines.push(`  --layout-${id}-${key}: ${value};`);
            }

            // Grid template (if provided)
            if (grid) {
                cssLines.push(`  display: grid;`);
                cssLines.push(`  grid-template: ${grid};`);
            }

            // Grid areas
            if (areas) {
                const areaEntries = Object.entries(areas);
                if (areaEntries.length) {
                    for (const [regionName, area] of areaEntries) {
                        cssLines.push(`  /* region: ${regionName} */`);
                    }
                }
            }

            cssLines.push(`}`);

            // Region-specific CSS
            for (const r of regions) {
                const regionLines = [];
                regionLines.push(`.layout-${id}__${r.name} {`);

                if (areas && areas[r.name]) {
                    regionLines.push(`  grid-area: ${areas[r.name]};`);
                }

                // Region-level token overrides as custom properties
                if (r.tokens) {
                    for (const [key, value] of Object.entries(r.tokens)) {
                        regionLines.push(`  --layout-${id}-${r.name}-${key}: ${value};`);
                    }
                }

                regionLines.push(`}`);
                cssLines.push(regionLines.join('\n'));
            }

            return {
                id,
                css: cssLines.join('\n'),
                loadOrder,
                regionMap,
            };
        },

        /**
         * Render the layout to real DOM elements.
         *
         * Creates a wrapper `<div class="layout-{id}">` containing one element
         * per region, each using the region's `tag`, `role`, and CSS class
         * `layout-{id}__{name}`.
         *
         * Returns a map of `{ container, regions: { [name]: Element } }` so
         * callers can populate each region slot with content.
         *
         * @param {object}  [opts={}]
         * @param {object}  [opts.classMap]  - Optional `{ regionName: 'extra-class' }` aliases.
         * @param {object}  [opts.attrs]     - Optional `{ regionName: { attrName: value } }`.
         * @param {string}  [opts.wrapperTag='div'] - Tag for the layout wrapper.
         * @returns {{ container: HTMLElement, regions: Record<string, HTMLElement> }}
         */
        render(opts = {}) {
            const { classMap = {}, attrs = {}, wrapperTag = 'div' } = opts;

            const container = document.createElement(wrapperTag);
            container.className = `layout-${id}`;

            // Apply token custom properties inline so they're available
            // immediately, before the async compileLayoutCSS() injects CSS.
            for (const [key, value] of Object.entries(tokens)) {
                container.style.setProperty(`--layout-${id}-${key}`, value);
            }

            const regionEls = {};

            for (const r of regions) {
                const el = document.createElement(r.tag);
                el.className = `layout-${id}__${r.name}`;

                // Append extra class aliases (e.g. 'docs-header')
                if (classMap[r.name]) {
                    el.classList.add(...classMap[r.name].split(/\s+/).filter(Boolean));
                }

                // ARIA role
                if (r.role) el.setAttribute('role', r.role);

                // Extra attributes
                if (attrs[r.name]) {
                    for (const [k, v] of Object.entries(attrs[r.name])) {
                        el.setAttribute(k, v);
                    }
                }

                container.appendChild(el);
                regionEls[r.name] = el;
            }

            return { container, regions: regionEls };
        },
    });
}
